class Solution {
    public int minimumScore(String s, String t) {
        int n = s.length(), m = t.length();
        int[] matchIndices = new int[m];
        int j = n - 1, matched = 0;
        for (int i = m - 1; i >= 0; i--) {
            while (j >= 0 && s.charAt(j) != t.charAt(i)) j--;
            if (j >= 0) {
                matchIndices[i] = j--;
                matched++;
            } else break;
        }

        if (matched == 0) return m;

        int minScore = matchIndices[0] + 1;
        int left = 0, right = matched - 1;
        for (int i = 1; i < m; i++) {
            if (matchIndices[i] == -1) continue;
            while (left < right && matchIndices[left + 1] < matchIndices[i] - (i - left - 1)) left++;
            minScore = Math.min(minScore, matchIndices[right] - matchIndices[left] + 1);
            if (matchIndices[right] < matchIndices[i] - (i - right)) right--;
        }
        return minScore;
    }
}
